package com.example.documentviewer;

import android.content.Intent;
import android.content.pm.PackageManager;
import android.net.Uri;
import android.os.Bundle;
import android.util.Log;
import androidx.appcompat.app.AppCompatActivity;
import java.io.File;

public class DocumentViewerActivity extends AppCompatActivity {
    private static final String TAG = "DocumentViewerActivity";
    private static final String PERMISSION_VIEW_DOCUMENTS = "com.example.permission.VIEW_DOCUMENTS";
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);
        
        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();
        
        if (Intent.ACTION_VIEW.equals(action) && intent.getData() != null) {
            Uri uri = intent.getData();
            
            if (!validateCaller(intent)) {
                Log.e(TAG, "Invalid caller attempted to access document");
                finish();
                return;
            }
            
            if (!validateUri(uri)) {
                Log.e(TAG, "Invalid URI received");
                finish();
                return;
            }
            
            displayDocument(uri);
        } else {
            Log.e(TAG, "Invalid intent received");
            finish();
        }
    }
    
    private boolean validateCaller(Intent intent) {
        String callerPackage = getCallingPackage();
        if (callerPackage == null) {
            return false;
        }
        
        try {
            PackageManager pm = getPackageManager();
            int permission = pm.checkPermission(PERMISSION_VIEW_DOCUMENTS, callerPackage);
            return permission == PackageManager.PERMISSION_GRANTED;
        } catch (Exception e) {
            Log.e(TAG, "Error validating caller", e);
            return false;
        }
    }
    
    private boolean validateUri(Uri uri) {
        if (uri == null) {
            return false;
        }
        
        try {
            String scheme = uri.getScheme();
            if (!"content".equals(scheme) && !"file".equals(scheme)) {
                return false;
            }
            
            String path = uri.getPath();
            if (path == null) {
                return false;
            }
            
            File file = new File(path);
            if (!file.exists()) {
                return false;
            }
            
            String mimeType = getContentResolver().getType(uri);
            if (mimeType == null) {
                return false;
            }
            
            return mimeType.startsWith("application/pdf") || 
                   mimeType.startsWith("image/");
        } catch (Exception e) {
            Log.e(TAG, "Error validating URI", e);
            return false;
        }
    }
    
    private void displayDocument(Uri uri) {
        // Implement document display logic here
        Log.d(TAG, "Displaying document: " + uri.toString());
    }
}